-- ── HNL-001 ──────────────────────────────────────────────────
INSERT INTO ppdm.well_log_curve_value
  (uwi,curve_id,sample_id,active_ind,source,
   index_type,index_value,index_value_uom,measured_value,measured_value_uom,
   row_created_by,row_created_date,row_changed_by,row_changed_date,
   row_effective_date,row_expiry_date,row_quality)
SELECT 'HNL-001','GR-HNL001','S'||LPAD(i::text,5,'0'),'Y','PERTAMINA',
  'MD',200.0+(i-1)*5.0,'M',
  GREATEST(5.0,LEAST(148.0, 65.0+30.0*SIN(i*0.08)+15.0*SIN(i*0.30+1.2)+8.0*SIN(i*1.5) )),
  'GAPI','SYSTEM',NOW(),'SYSTEM',NOW(),NOW(),'9999-12-31','MEDIUM'
FROM generate_series(1,651) i ON CONFLICT DO NOTHING;

